--- /dev/null
+++ b/src/middleware/rateLimit.ts
@@ -0,0 +1,15 @@
+import { Request, Response, NextFunction } from 'express';
+
+const windowMs = 60 * 1000;
+const store = new Map<string, { count: number; resetAt: number }>();
+
+export function rateLimit(maxRequests: number) {
+  return (req: Request, res: Response, next: NextFunction) => {
+    const key = req.ip || 'unknown';
+    const now = Date.now();
+    const entry = store.get(key);
+    if (!entry || now > entry.resetAt) { store.set(key, { count: 1, resetAt: now + windowMs }); return next(); }
+    if (entry.count >= maxRequests) { return res.status(429).json({ error: 'Rate limit exceeded' }); }
+    entry.count++; next();
+  };
+}

